sql:
SELECT * 
FROM socioeconomic_factors
WHERE factor_name IN ('Median Income', 'Poverty Rate');

external_knowledge:
1. 'bustling metropolis garden' - refers to states with high populations and densities;
2. 'vibrant population density flowers blooming' - metaphor for states with high average population density;
3. 'more than a million inhabitants' - condition for the state's population;
4. 'thriving in the fertile data grounds updated after the winter solstice of 2021' - data sources updated after January 1, 2022.

sql:
SELECT d.chsi_state_abbr, ho.health_indicator
FROM demographics d
INNER JOIN health_outcomes ho ON d.demographic_id = ho.demographic_id;

SELECT source_name, last_updated 
FROM data_sources 
ORDER BY last_updated DESC;

SELECT demographic_id, state_fips_code, county_fips_code, chsi_county_name, chsi_state_name, chsi_state_abbr, population
FROM demographics
WHERE demographic_id = 0;

SELECT chsi_county_name 
FROM demographics 
WHERE population_density = (SELECT MIN(population_density) FROM demographics);

SELECT AVG(population) 
FROM demographics 
WHERE chsi_state_name = 'California';

external_knowledge:
- "blossoming microcosms" refers to small counties;
- "Golden State" is a metaphor for California;
- "nestled within 100 square miles or less" means the area is 100 square miles or less;
- "densest crowd of residents" refers to high population density;
- "cramped quarters to the most spacious" indicates the sorting order from highest to lowest population density.

sql:
SELECT AVG(population) AS 'Average population'
FROM demographics
WHERE chsi_state_abbr = 'CA' AND data_source_id BETWEEN 20200101 AND 20201231;
